import React, { useState, useCallback } from 'react';
import { useParams } from 'react-router-dom';
import { useInAppNavigate } from '../../../router/useInAppNavigate';
import { Button, dispatchAppToast } from '@linm-soft-org/linm-web-common-components';
import { DocumentProcessingLevelPill } from '../../../components/document/DocumentProcessingLevelPill';
import {
  DOCUMENT_APPROVED_LEVEL,
  DOCUMENT_ENTRY_LEVEL,
  DOCUMENT_PREPARED_LEVEL,
  formatCostSheetProcessingLevel,
  isFinalDocumentProcessingLevel,
} from '../../../utils/documentProcessingLevelDisplay';
import { useAppDispatch } from '../../../store/hooks';
import { gtService } from '../../../services/gt/gtService';
import type { CostSheetDto, CostElementDto, WipBalanceDto } from '../../../services/gt/models';
import type { DocumentPostingStatus } from '../../../services/kt/models';
import { formatVnd } from '../../../utils/formatters';
import { getApiErrorMessage } from '../../../utils/getApiErrorMessage';
import { pollDocumentPostingStatus } from '../../../utils/pollDocumentPostingStatus';
import { VoucherPostedLedgerModal } from '../../../components/voucher/VoucherPostedLedgerModal';
import { giaThanhPageLabels as L } from '../../../constants/giaThanhPageLabels';
import { useCostSheetPermissions } from '../../../hooks/useCostSheetPermissions';
import erp from '../../../styles/erpPage.module.css';

const GiaThanhDetailPage: React.FC = () => {
  const { id } = useParams<{ id: string }>();
  const navigate = useInAppNavigate();
  const dispatch = useAppDispatch();
  const { canRead, canRun, canApprove, canPost, canViewLedger: canViewLedgerPerm } =
    useCostSheetPermissions();
  const [sheet, setSheet] = useState<CostSheetDto | null>(null);
  const [elements, setElements] = useState<CostElementDto[]>([]);
  const [wipRow, setWipRow] = useState<WipBalanceDto | null>(null);
  const [loading, setLoading] = useState(false);
  const [acting, setActing] = useState(false);
  const [postingStatus, setPostingStatus] = useState<DocumentPostingStatus>('None');
  const [ledgerOpen, setLedgerOpen] = useState(false);

  const load = useCallback(() => {
    if (!id || !canRead) return;
    setLoading(true);
    Promise.all([
      gtService.getCostSheet(id),
      gtService.getCostElements(id),
      gtService.getCostSheetPostingStatus(id),
    ])
      .then(async ([s, els, ps]) => {
        setSheet(s);
        setElements(els);
        setPostingStatus(ps.postingStatus);
        const wip = await gtService.getWipBalance(s.month, s.year);
        setWipRow(wip.find(row => row.productionOrderCode === s.productionOrderCode) ?? null);
      })
      .catch(err => dispatchAppToast(dispatch, { message: getApiErrorMessage(err, L.detail.loadError), type: 'error' }))
      .finally(() => setLoading(false));
  }, [id, canRead, dispatch]);

  React.useEffect(() => {
    let cancelled = false;
    const t = setTimeout(() => { if (!cancelled) load(); }, 0);
    return () => { cancelled = true; clearTimeout(t); };
  }, [load]);

  const handleCalculate = async () => {
    if (!sheet) return;
    setActing(true);
    try {
      await gtService.calculateCosts(sheet.month, sheet.year);
      dispatchAppToast(dispatch, { message: L.detail.calculateSuccess, type: 'success' });
      load();
    } catch (e: unknown) {
      dispatchAppToast(dispatch, { message: getApiErrorMessage(e, L.detail.calculateError), type: 'error' });
    } finally {
      setActing(false);
    }
  };

  const handleApprove = async () => {
    if (!id) return;
    setActing(true);
    try {
      await gtService.approveCostSheet(id);
      dispatchAppToast(dispatch, { message: L.detail.approveSuccess, type: 'success' });
      load();
    } catch (e: unknown) {
      dispatchAppToast(dispatch, { message: getApiErrorMessage(e, L.detail.approveError), type: 'error' });
    } finally {
      setActing(false);
    }
  };

  const handlePost = async () => {
    if (!id) return;
    setActing(true);
    try {
      const result = await gtService.postCostSheet(id);
      setPostingStatus(result.postingStatus);
      if (result.postingStatus === 'Queued' || result.postingStatus === 'Processing') {
        const final = await pollDocumentPostingStatus(() => gtService.getCostSheetPostingStatus(id));
        setPostingStatus(final.postingStatus);
        if (final.postingStatus === 'Failed' && final.lastError) {
          dispatchAppToast(dispatch, { message: final.lastError, type: 'error' });
        } else if (final.postingStatus === 'Posted') {
          dispatchAppToast(dispatch, { message: L.detail.postSuccess, type: 'success' });
        }
      } else if (result.postingStatus === 'Posted') {
        dispatchAppToast(dispatch, { message: L.detail.postSuccess, type: 'success' });
      }
      load();
    } catch (e: unknown) {
      dispatchAppToast(dispatch, { message: getApiErrorMessage(e, L.detail.postError), type: 'error' });
    } finally {
      setActing(false);
    }
  };

  if (loading) return <div className={erp.loading} data-testid="erp-gia-thanh-detail-loading">{L.detail.loading}</div>;
  if (!sheet) {
    return (
      <div className={erp.page} data-testid="erp-gia-thanh-detail-empty">
        <div className={erp.pageHeader}>
          <button type="button" className={erp.codeLink} onClick={() => navigate('/gt/gia-thanh')}>{L.detail.back}</button>
        </div>
        <div className={erp.empty}>{L.detail.notFound}</div>
      </div>
    );
  }

  const level = sheet.processingLevel ?? DOCUMENT_ENTRY_LEVEL;
  const canCalculate = level === DOCUMENT_ENTRY_LEVEL && canRun;
  const showApprove =
    (level === DOCUMENT_ENTRY_LEVEL || level === DOCUMENT_PREPARED_LEVEL) && canApprove;
  const showPost = level === DOCUMENT_APPROVED_LEVEL && canPost;
  const canViewLedger =
    canViewLedgerPerm &&
    (isFinalDocumentProcessingLevel(level) ||
      postingStatus === 'Posted' ||
      postingStatus === 'Processing' ||
      postingStatus === 'Queued');

  return (
    <div className={erp.page} data-testid="erp-gia-thanh-detail">
      <div className={erp.pageHeader}>
        <div className={erp.titleBlock}>
          <button type="button" className={erp.codeLink} onClick={() => navigate('/gt/gia-thanh')}>{L.detail.back}</button>
          <h1 className={erp.title}>
            {L.detail.titlePrefix} {sheet.code}{' '}
            <DocumentProcessingLevelPill
              label={formatCostSheetProcessingLevel(sheet.processingLevel)}
              testId="erp-gia-thanh-detail-level"
            />
          </h1>
        </div>
        <div className={erp.headerActions}>
          {canCalculate && (
            <Button variant="secondary" disabled={acting} onClick={handleCalculate} data-testid="erp-gia-thanh-calculate">
              {L.detail.calculate}
            </Button>
          )}
          {showApprove && (
            <Button variant="secondary" disabled={acting} onClick={handleApprove} data-testid="erp-gia-thanh-approve">
              {L.detail.approve}
            </Button>
          )}
          {showPost && (
            <Button variant="primary" disabled={acting} onClick={handlePost} data-testid="erp-gia-thanh-post">
              {L.detail.post}
            </Button>
          )}
          {canViewLedger && id && (
            <Button variant="secondary" onClick={() => setLedgerOpen(true)} data-testid="erp-gia-thanh-view-ledger">
              {L.detail.viewLedger}
            </Button>
          )}
        </div>
      </div>
      {(postingStatus === 'Queued' || postingStatus === 'Processing') && (
        <div className={erp.summaryBar} data-testid="erp-gia-thanh-posting-banner">
          <div className={erp.summaryItem}>
            <strong>{postingStatus === 'Processing' ? L.detail.postingProcessing : L.detail.postingQueued}</strong>
          </div>
        </div>
      )}
      <div className={erp.summaryBar}>
        <div className={erp.summaryItem}><label className={erp.label}>{L.detail.product}</label><strong>{sheet.productName ?? sheet.productCode}</strong></div>
        <div className={erp.summaryItem}><label className={erp.label}>{L.detail.order}</label><strong>{sheet.productionOrderCode ?? '—'}</strong></div>
        <div className={erp.summaryItem}><label className={erp.label}>{L.detail.period}</label><strong>{sheet.month}/{sheet.year}</strong></div>
        <div className={erp.summaryItem}><label className={erp.label}>{L.detail.actualQty}</label><strong>{sheet.actualQty}</strong></div>
        <div className={erp.summaryItem}><label className={erp.label}>{L.detail.totalCost}</label><strong>{formatVnd(sheet.totalCost)}</strong></div>
        <div className={erp.summaryItem}><label className={erp.label}>{L.detail.unitCost}</label><strong>{formatVnd(sheet.unitCost)}</strong></div>
      </div>
      {wipRow && (
        <div className={erp.summaryBar} data-testid="erp-gia-thanh-detail-wip">
          <div className={erp.summaryItem}><label className={erp.label}>{L.detail.wipOpening}</label><strong>{formatVnd(wipRow.openingAmount)}</strong></div>
          <div className={erp.summaryItem}><label className={erp.label}>{L.detail.wipIn}</label><strong>{formatVnd(wipRow.inAmount)}</strong></div>
          <div className={erp.summaryItem}><label className={erp.label}>{L.detail.wipOut}</label><strong>{formatVnd(wipRow.outAmount)}</strong></div>
          <div className={erp.summaryItem}><label className={erp.label}>{L.detail.wipClosing}</label><strong>{formatVnd(wipRow.closingAmount)}</strong></div>
        </div>
      )}
      <div className={erp.tableCard} data-testid="erp-gia-thanh-elements-table">
        <div className={erp.tableWrapper}>
          <table className={erp.table}>
            <thead>
              <tr>
                <th>{L.detail.colElementType}</th>
                <th>{L.detail.colDescription}</th>
                <th>{L.detail.colAccount}</th>
                <th className={erp.colRight}>{L.detail.colAmount}</th>
              </tr>
            </thead>
            <tbody>{elements.map((el, i) => (
              <tr key={el.id ?? i}>
                <td>{el.elementType}</td>
                <td>{el.description}</td>
                <td><code>{el.accountCode}</code></td>
                <td className={erp.colRight}>{formatVnd(el.amount)}</td>
              </tr>
            ))}</tbody>
          </table>
        </div>
      </div>
      {id && (
        <VoucherPostedLedgerModal
          isOpen={ledgerOpen}
          onClose={() => setLedgerOpen(false)}
          testIdPrefix="erp-gia-thanh-ledger"
          voucherTitle={sheet.code}
          fetchPostedLedger={() => gtService.getCostSheetPostedLedger(id)}
          fetchPostingStatus={() => gtService.getCostSheetPostingStatus(id)}
        />
      )}
    </div>
  );
};

export default GiaThanhDetailPage;
