import React from 'react';
import { Tooltip, useViewMobileLayout } from '@linm-soft-org/linm-web-common-components';

export type ReportAccountCodeCellProps = {
  code?: string | null;
  name?: string | null;
  testId?: string;
};

/** Báo cáo chi tiết KT — cell chỉ mã; tên TK tooltip (hover desktop · nhấn giữ mobile). */
export function ReportAccountCodeCell({ code, name, testId }: ReportAccountCodeCellProps): React.ReactElement | null {
  const viewMobile = useViewMobileLayout();
  const trimmedCode = code?.trim();
  if (!trimmedCode) return null;

  const trimmedName = name?.trim();

  if (!trimmedName) {
    return (
      <code data-testid={testId}>
        {trimmedCode}
      </code>
    );
  }

  if (viewMobile) {
    return (
      <code title={trimmedName} data-testid={testId}>
        {trimmedCode}
      </code>
    );
  }

  return (
    <Tooltip content={trimmedName} inline trigger="hover" allowWrap maxWidth={320}>
      <code data-testid={testId}>
        {trimmedCode}
      </code>
    </Tooltip>
  );
}
